import{_ as e,o as r,c as l,a1 as t}from"./chunks/framework.CSfPkKfr.js";const f=JSON.parse('{"title":"域名托管与 CDN 加速避坑指南","description":"","frontmatter":{"title":"域名托管与 CDN 加速避坑指南","date":"2026-03-29T00:00:00.000Z"},"headers":[],"relativePath":"tools/cloudflare-cdn.md","filePath":"tools/cloudflare-cdn.md"}'),a={name:"tools/cloudflare-cdn.md"};function s(d,o,n,c,i,u){return r(),l("div",null,[...o[0]||(o[0]=[t('<h1 id="域名托管与-cdn-加速避坑指南" tabindex="-1">域名托管与 CDN 加速避坑指南 <a class="header-anchor" href="#域名托管与-cdn-加速避坑指南" aria-label="Permalink to &quot;域名托管与 CDN 加速避坑指南&quot;">​</a></h1><p>本文总结了基于 VitePress、GitHub Pages 和 Cloudflare CDN 建站时的常见坑点。</p><h2 id="cloudflare-pages-部署大坑" tabindex="-1">Cloudflare Pages 部署大坑 <a class="header-anchor" href="#cloudflare-pages-部署大坑" aria-label="Permalink to &quot;Cloudflare Pages 部署大坑&quot;">​</a></h2><ol><li><p><strong>极其容易走错入口（千万别选 Workers）</strong>： 在 Cloudflare 绑定 GitHub 代码仓库时，必须进入 <strong>Pages</strong> 选项卡下点击“连接到 Git”。切忌点进 <strong>Workers</strong> 流程，因为 Workers 没有静态网站目录配置选项。</p></li><li><p><strong>输出目录必须精确匹配</strong>： 如果你的 VitePress 是初始化在代码仓库的 <code>docs</code> 目录下的，那么在 Cloudflare 设置里：</p><ul><li><strong>构建命令</strong>: <code>npm run docs:build</code></li><li><strong>构建输出目录必须是</strong>: <code>docs/.vitepress/dist</code> 如果你误写为 <code>.vitepress/dist</code> 或者少写了前置目录，Cloudflare 在部署完后会找不到产物，直接报错 <code>522 Connection Timed Out</code> 或 <code>404</code>。</li></ul></li><li><p><strong>语法错误检查</strong>： 你的本地 <code>config.js</code> 必须确保没有语法错误。若不小心多加了一个转义符或者逗号，会导致 <code>npm run docs:build</code> 直接编译失败。</p></li></ol><h2 id="免费二级域名与-cdn-托管的冲突" tabindex="-1">免费二级域名与 CDN 托管的冲突 <a class="header-anchor" href="#免费二级域名与-cdn-托管的冲突" aria-label="Permalink to &quot;免费二级域名与 CDN 托管的冲突&quot;">​</a></h2><p>很多新手想用免费的二级子域名（如 ClouDNS 提供的 <code>.abrdns.com</code>）绑定 Cloudflare 加速，但实测会<strong>直接被拦截报错</strong>。</p><ul><li><strong>原因</strong>：这类免费二级域名平台通常会锁死 <strong>NS（名称服务器）</strong> 修改权限。</li><li><strong>正解</strong>：Cloudflare 接管域名必须要修改根域名的 NS。因此，如果需要用 CDN 加速、防 DDoS，<strong>必须购买顶级域名（如 .xyz、.top 等，首年极低，通常仅需 5-10 元）</strong>，才能完美挂载到 Cloudflare。</li><li><em>备注</em>：DuckDNS 只能用于动态 IP 解析直连，也不能托管给 Cloudflare。</li></ul>',7)])])}const p=e(a,[["render",s]]);export{f as __pageData,p as default};
